 50→function filterSections(sections: SectionData[], query: string): SectionData[] {
 51→  if (!query) return sections;
 52→  const lower = query.toLowerCase();
 53→  return sections
 54→    .map(section => ({
 55→      ...section,
 56→      items: section.items.filter(
 57→        item =>
 58→          item.title.toLowerCase().includes(lower) ||
 59→          item.subtitle?.toLowerCase().includes(lower),
 60→      ),
 61→    }))
 62→    .filter(section => section.items.length > 0);
 63→}
 64→
 65→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 66→  if (!query) return colors;
 67→  const lower = query.toLowerCase();
 68→  return colors.filter(
 69→    c =>
 70→      c.title.toLowerCase().includes(lower) ||
 71→      c.subtitle?.toLowerCase().includes(lower),
 72→  );
 73→}
 74→
 75→function flattenItems(sections: SectionData[]): ListItemData[] {
 76→  return sections.flatMap(s => s.items);
 77→}
 78→
 79→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 80→  switch (entry.type) {
 81→    case 'label':
 82→      return (
 83→        <DetailMetadata.Label
 84→          key={index}
 85→          title={entry.title}
 86→          text={entry.text}
 87→        />
 88→      );
 89→    case 'link':
 90→      return (
 91→        <DetailMetadata.Link
 92→          key={index}
 93→          title={entry.title}
 94→          text={entry.text}
 95→          target={entry.target}
 96→        />
 97→      );
 98→    case 'tag-list':
 99→      return (
100→        <DetailMetadata.TagList key={index} title={entry.title}>
101→          {entry.tags.map(tag => (
102→            <DetailMetadata.Tag
103→              key={tag.text}
104→              text={tag.text}
105→              color={tag.color}
106→            />
107→          ))}
108→        </DetailMetadata.TagList>
109→      );
110→    case 'separator':
111→      return <DetailMetadata.Separator key={index} />;
112→  }
113→}
