183→interface ColorPickerViewProps {
184→  colors: ColorItemData[];
185→  onActiveIndexChange: (index: number) => void;
186→  onAction: (index: number) => void;
187→}
188→
189→function ColorPickerView({
190→  colors,
191→  onActiveIndexChange,
192→  onAction,
193→}: ColorPickerViewProps) {
194→  if (colors.length === 0) {
195→    return (
196→      <EmptyState
197→        icon={<SearchIcon />}
198→        title="No Colors"
199→        description="Try a different search term"
200→      />
201→    );
202→  }
203→
204→  return (
205→    <Grid
206→      itemCount={colors.length}
207→      columns={4}
208→      onActiveIndexChange={onActiveIndexChange}
209→      onAction={onAction}
210→    >
211→      {colors.map((color, index) => (
212→        <GridItem
213→          key={color.id}
214→          index={index}
215→          icon={<ColorSwatch color={color.color} />}
216→          title={color.title}
217→          subtitle={color.subtitle}
218→        />
219→      ))}
220→    </Grid>
221→  );
222→}
223→
224→function DetailView({ item }: { item: ListItemData }) {
225→  const itemDetail = item.detail;
226→  if (!itemDetail) return null;
227→  return (
228→    <Detail
229→      markdown={itemDetail.markdown}
230→      metadata={
231→        itemDetail.metadata ? (
232→          <DetailMetadata>
233→            {itemDetail.metadata.map(renderMetadataEntry)}
234→          </DetailMetadata>
235→        ) : undefined
236→      }
237→    />
238→  );
239→}
