241→export function App() {
242→  const [query, setQuery] = useState('');
243→  const [filterValue, setFilterValue] = useState('all');
244→  const [colorFilterValue, setColorFilterValue] = useState('all');
245→  const [selectedIndex, setSelectedIndex] = useState(0);
246→  const [actionsOpen, setActionsOpen] = useState(false);
247→  const [quickLookOpen, setQuickLookOpen] = useState(false);
248→  const { toasts, show: showToast, hide: hideToast } = useToast();
249→  const { items: hudItems, show: showHUD } = useHUD();
250→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
251→  const nav = useNavigationStack<NavViewData>('Raycast');
252→  const { push } = nav;
253→
254→  const viewType = nav.currentEntry?.data.type ?? 'root';
255→
256→  const searchFilterSections: SearchDropdownSection[] = useMemo(
257→    () => [
258→      {
259→        options: [
260→          {
261→            label: 'All',
262→            value: 'all',
263→          },
264→        ],
265→      },
266→      {
267→        title: 'Types',
268→        options: [
269→          {
270→            label: 'Commands',
271→            value: 'commands',
272→          },
273→          {
274→            label: 'Applications',
275→            value: 'applications',
276→          },
277→        ],
278→      },
279→    ],
280→    [],
281→  );
282→
283→  const colorFilterSections: SearchDropdownSection[] = useMemo(
284→    () => [
285→      {
286→        options: [
287→          {
288→            label: 'All Colors',
289→            value: 'all',
290→          },
291→        ],
292→      },
293→      {
294→        title: 'Category',
295→        options: [
296→          {
297→            label: 'Warm',
298→            value: 'warm',
299→          },
300→          {
301→            label: 'Cool',
302→            value: 'cool',
303→          },
304→          {
305→            label: 'Neutral',
306→            value: 'neutral',
307→          },
308→        ],
309→      },
310→    ],
311→    [],
312→  );
313→
314→  useEffect(() => {
315→    if (nav.stackDepth === 0) {
316→      setQuery('');
317→      setFilterValue('all');
318→      setColorFilterValue('all');
319→      setSelectedIndex(0);
320→      setActionsOpen(false);
321→      setQuickLookOpen(false);
322→    }
323→  }, [nav.stackDepth]);
324→
325→  const filtered = useMemo(() => {
326→    let sections = MOCK_SECTIONS;
327→    if (filterValue === 'commands') {
328→      sections = sections.filter(
329→        s => s.title === 'Suggestions' || s.title === 'Commands',
330→      );
331→    } else if (filterValue === 'applications') {
332→      sections = sections.filter(s => s.title === 'Applications');
333→    }
334→    return filterSections(sections, query);
335→  }, [
336→    query,
337→    filterValue,
338→  ]);
339→  const calculatorResult = useMemo(() => {
340→    if (viewType !== 'root' || !query.trim()) return null;
341→    return evaluate(query);
342→  }, [
343→    query,
344→    viewType,
345→  ]);
346→
347→  const allItems = useMemo(() => {
348→    const items = flattenItems(filtered);
349→    if (calculatorResult) {
350→      const calcItem: ListItemData = {
351→        id: '__calculator__',
352→        title: `= ${calculatorResult}`,
353→        subtitle: query.trim(),
354→        icon: <CalculatorIcon />,
355→      };
356→      return [
357→        calcItem,
358→        ...items,
359→      ];
360→    }
361→    return items;
362→  }, [
363→    filtered,
364→    calculatorResult,
365→    query,
366→  ]);
367→  const filteredColors = useMemo(() => {
368→    let colors = MOCK_COLORS;
369→    if (colorFilterValue !== 'all') {
370→      colors = colors.filter(c => c.category === colorFilterValue);
371→    }
372→    return filterColors(colors, query);
373→  }, [
374→    query,
375→    colorFilterValue,
376→  ]);
377→
378→  const selectedItem =
379→    viewType === 'root' ? allItems[selectedIndex] : undefined;
380→
381→  const handleQueryChange = useCallback((value: string) => {
382→    setQuery(value);
383→    setSelectedIndex(0);
384→    setActionsOpen(false);
385→  }, []);
386→
387→  const handleFilterChange = useCallback((value: string) => {
388→    setFilterValue(value);
389→    setSelectedIndex(0);
390→  }, []);
391→
392→  const handleColorFilterChange = useCallback((value: string) => {
393→    setColorFilterValue(value);
394→    setSelectedIndex(0);
395→  }, []);
396→
397→  const handleActiveIndexChange = useCallback((index: number) => {
398→    setSelectedIndex(index);
399→    setActionsOpen(false);
400→  }, []);
401→
402→  const handleCopyColor = useCallback(
403→    (color: ColorItemData) => {
404→      showHUD({
405→        icon: <ClipboardHUDIcon />,
406→        title: `Copied ${color.color}`,
407→      });
408→    },
409→    [showHUD],
410→  );
411→
412→  const handleGridAction = useCallback(
413→    (index: number) => {
414→      const color = filteredColors[index];
415→      if (color) {
416→        handleCopyColor(color);
417→      }
418→    },
419→    [
420→      filteredColors,
421→      handleCopyColor,
422→    ],
423→  );
424→
425→  const handleDrillIn = useCallback(() => {
426→    const item = allItems[selectedIndex];
427→    if (!item) return;
428→
429→    setActionsOpen(false);
430→
431→    if (item.id === '__calculator__') {
432→      showHUD({
433→        icon: <ClipboardHUDIcon />,
434→        title: `Copied ${calculatorResult}`,
435→      });
436→      return;
437→    }
438→
439→    if (item.id === 'clipboard-history') {
440→      push('Clipboard History', { type: 'clipboard' });
441→      setQuery('');
442→      setSelectedIndex(0);
443→    } else if (item.id === 'file-search') {
444→      push('File Search', { type: 'file-search' });
445→      setQuery('');
446→      setSelectedIndex(0);
447→    } else if (item.id === 'snippets') {
448→      push('Snippets', { type: 'snippets' });
449→      setQuery('');
450→      setSelectedIndex(0);
451→    } else if (item.id === 'emoji') {
452→      push('Search Emoji', { type: 'emoji' });
453→      setQuery('');
454→      setSelectedIndex(0);
455→    } else if (item.id === 'color-picker') {
456→      push('Color Picker', { type: 'grid' });
457→      setQuery('');
458→      setSelectedIndex(0);
459→      setColorFilterValue('all');
460→      showToast({
461→        style: 'success',
462→        title: 'Opened Color Picker',
463→      });
464→    } else if (item.detail) {
465→      push(item.title, {
466→        type: 'detail',
467→        item,
468→      });
469→      setQuery('');
470→      showToast({
471→        style: 'success',
472→        title: `Opened ${item.title}`,
473→      });
474→    } else {
475→      showToast({
476→        style: 'success',
477→        title: `Opened ${item.title}`,
478→      });
479→    }
480→  }, [
481→    allItems,
482→    selectedIndex,
483→    showToast,
484→    showHUD,
485→    calculatorResult,
486→    push,
487→  ]);
488→
489→  const toggleActions = useCallback(() => {
490→    setActionsOpen(prev => !prev);
491→  }, []);
492→
493→  const closeActions = useCallback(() => {
494→    setActionsOpen(false);
495→  }, []);
496→
497→  useKeyboardShortcut(
498→    {
499→      key: 'k',
500→      meta: true,
501→    },
502→    toggleActions,
503→    {
504→      enabled:
505→        viewType !== 'clipboard' &&
506→        viewType !== 'snippets' &&
507→        viewType !== 'emoji' &&
508→        viewType !== 'file-search',
509→    },
510→  );
511→
512→  const toggleQuickLook = useCallback(() => {
513→    setQuickLookOpen(prev => !prev);
514→  }, []);
515→
516→  const closeQuickLook = useCallback(() => {
517→    setQuickLookOpen(false);
518→  }, []);
519→
520→  useKeyboardShortcut(
521→    {
522→      key: 'y',
523→      meta: true,
524→    },
525→    toggleQuickLook,
526→    { enabled: viewType === 'root' && !!selectedItem?.detail },
527→  );
528→
529→  useEffect(() => {
530→    if (viewType !== 'root' || !selectedItem?.detail) return;
531→
532→    function handleSpaceBar(e: KeyboardEvent) {
533→      if (e.key !== ' ' || e.metaKey || e.ctrlKey || e.altKey) {
534→        return;
535→      }
536→      if (query !== '') return;
537→
538→      e.preventDefault();
539→      e.stopPropagation();
540→      setQuickLookOpen(prev => !prev);
541→    }
542→
543→    window.addEventListener('keydown', handleSpaceBar);
544→    return () => window.removeEventListener('keydown', handleSpaceBar);
545→  }, [
546→    viewType,
547→    selectedItem?.detail,
548→    query,
549→  ]);
550→
551→  const isCalculatorSelected = selectedItem?.id === '__calculator__';
552→  const detail = isCalculatorSelected ? undefined : selectedItem?.detail;
553→
554→  const dropdownSections = useMemo(
555→    () => [
556→      {
557→        title: 'Primary Actions',
558→        actions: [
559→          {
560→            label: isCalculatorSelected ? 'Copy Result' : 'Open',
561→            shortcut: <Kbd keys={['↵']} />,
562→            onClick: () => {
563→              if (isCalculatorSelected && calculatorResult) {
564→                showHUD({
565→                  icon: <ClipboardHUDIcon />,
566→                  title: `Copied ${calculatorResult}`,
567→                });
568→              } else if (selectedItem) {
569→                showToast({
570→                  style: 'success' as const,
571→                  title: `Opened ${selectedItem.title}`,
572→                });
573→              }
574→            },
575→          },
576→          {
577→            label: 'Quick Look',
578→            shortcut: (
579→              <Kbd
580→                keys={[
581→                  '⌘',
582→                  'Y',
