656→        />
657→        <div className="command-palette__body">
658→          <div className="command-palette__list-container">
659→            <EditSnippetView
660→              snippet={subView === 'edit' ? editingSnippet : undefined}
661→              onSubmit={handleFormSubmit}
662→            />
663→          </div>
664→        </div>
665→        <ActionPanel
666→          contextLabel={formTitle}
667→          actions={[
668→            {
669→              label: 'Submit',
670→              shortcut: (
671→                <Kbd
672→                  keys={[
