674→                    '↵',
675→                  ]}
676→                />
677→              ),
678→            },
679→          ]}
680→          dropdownOpen={false}
681→          dropdownSections={[]}
682→          onDropdownClose={() => {}}
683→        />
684→        <HUDContainer items={hudItems} />
685→      </>
686→    );
687→  }
688→
689→  return (
690→    <>
691→      <SearchBar
692→        value={query}
693→        onChange={handleQueryChange}
694→        placeholder="Search Snippets..."
695→        activeDescendantId={activeDescendantId}
