  ], [handleCopy, handleDelete]);

  // 6. FULL-SCREEN LAYOUT (always this structure)
  return (
    <>
      <SearchBar
        value={query}
        onChange={handleQueryChange}
        placeholder="Search Clipboard..."
        activeDescendantId={activeDescendantId}
