  { key: string, meta?: boolean, ctrl?: boolean, alt?: boolean, shift?: boolean },
  handler: (e: KeyboardEvent) => void,
  options?: { enabled?: boolean, preventDefault?: boolean }
);
// Examples:
// { key: 'k', meta: true }  => ⌘K
// { key: 'Enter', meta: true } => ⌘Enter
// { key: 'p', ctrl: true } => Ctrl+P (Emacs navigation)
